// Selector inteligente de productos basado en conversiones
const products = $input.all()[0].json.search_results || [];
const psychProfile = $('AI Psychological Profiler').all()[0].json.choices[0].message.content;
const country = $('Set Country-Specific Variables').all()[0].json.country;
const affiliateTag = $('Set Country-Specific Variables').all()[0].json.affiliateTag;

// Algoritmo de scoring de productos
const scoredProducts = products.map(product => {
  let score = 0;

  // Score por rating (40% del score total)
  if (product.rating) {
    score += (product.rating / 5) * 40;
  }

  // Score por número de reviews (30% del score total) 
  if (product.ratings_total) {
    const reviewScore = Math.min(product.ratings_total / 1000, 1) * 30;
    score += reviewScore;
  }

  // Score por precio (20% del score total) - productos entre $20-$200 son óptimos
  if (product.price?.value) {
    const price = product.price.value;
    if (price >= 20 && price <= 200) {
      score += 20;
    } else if (price > 200 && price <= 500) {
      score += 15;
    } else {
      score += 5;
    }
  }

  // Score por disponibilidad (10% del score total)
  if (product.is_prime) score += 5;
  if (product.is_amazon_choice) score += 5;

  return {
    ...product,
    conversionScore: score,
    affiliateUrl: `https://${$('Set Country-Specific Variables').all()[0].json.amazonDomain}/dp/${product.asin}?tag=${affiliateTag}`
  };
});

// Ordenar por score y tomar los top 5
const topProducts = scoredProducts
  .sort((a, b) => b.conversionScore - a.conversionScore)
  .slice(0, 5);

return topProducts.map(product => ({ json: product }));

